CREATE TABLE `OD_ORDER_LABEL_HEAD` (
  `ID_DLK_ORDER_LABEL_HEAD` int NOT NULL AUTO_INCREMENT COMMENT 'Id Unico de la cabecera de etiqueta',
  `ID_DLK_ORDER_HEAD` int NOT NULL COMMENT 'FK a OD_ORDER_HEAD',
  `ID_DLK_DIGITAL_IDENTIFIER` int NOT NULL COMMENT 'FK al catálogo MD_DIGITAL_IDENTIFIER',
  `ID_DLK_ORDER_DETAIL` int DEFAULT NULL COMMENT 'FK al colorway (OD_ORDER_DETAIL)',
  `COD_ORDER_LABEL` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Código corto de la cabecera de etiqueta',
  `COD_ESTILO` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Código del estilo asociado',
  `NAME_ESTILO` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Nombre del estilo',
  `DESCRIPTION_ESTILO` text COLLATE utf8mb4_unicode_ci,
  `GENDER_ESTILO` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `SEASON_ESTILO` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `COD_GTIN` varchar(14) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'GTIN-14 base que se usa para los sGTIN',
  `ESTAMPADO` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Estampado del modelo/colorway',
  `IDENTIFIER_TYPE` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Tipo de identificador efectivo (snapshot)',
  `IDENTIFIER_MATERIAL` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `IDENTIFIER_LOCATION` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `INICIO_SERIALIZACION` int DEFAULT NULL COMMENT 'Número inicial del rango serializado',
  `FIN_SERIALIZACION` int DEFAULT NULL COMMENT 'Número final del rango serializado',
  `TOTAL_LABEL` int DEFAULT NULL COMMENT 'Total de unidades serializadas (FIN - INICIO + 1)',
  `SIGN_OPEN_RESPONSIBLE` text COLLATE utf8mb4_unicode_ci COMMENT 'Firma de apertura (base64 o ref)',
  `FEH_SIGN_OPEN` datetime(3) DEFAULT NULL,
  `SIGN_CLOSE_RESPONSIBLE` text COLLATE utf8mb4_unicode_ci,
  `FEH_SIGN_CLOSE` datetime(3) DEFAULT NULL,
  `DIGITAL_CERTIFICATE_ID` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `STATE_ORDER_LABEL_HEAD` tinyint(1) DEFAULT '1' COMMENT '1=Activo, 0=Inactivo',
  `COD_USUARIO_CARGA_DL` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `FEH_PROCESO_CARGA_DL` datetime(3) DEFAULT CURRENT_TIMESTAMP(3),
  `FEH_PROCESO_MODIF_DL` datetime(3) DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  `DES_ACCION` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `FLG_STATUT_ACTIF` tinyint(1) DEFAULT '1',
  PRIMARY KEY (`ID_DLK_ORDER_LABEL_HEAD`),
  KEY `idx_label_head_order` (`ID_DLK_ORDER_HEAD`),
  KEY `idx_label_head_digital_id` (`ID_DLK_DIGITAL_IDENTIFIER`),
  KEY `fk_label_head_order_detail` (`ID_DLK_ORDER_DETAIL`),
  CONSTRAINT `fk_label_head_digital_master` FOREIGN KEY (`ID_DLK_DIGITAL_IDENTIFIER`) REFERENCES `MD_DIGITAL_IDENTIFIER` (`ID_DLK_DIGITAL_IDENTIFIER`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_label_head_order` FOREIGN KEY (`ID_DLK_ORDER_HEAD`) REFERENCES `OD_ORDER_HEAD` (`ID_DLK_ORDER_HEAD`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_label_head_order_detail` FOREIGN KEY (`ID_DLK_ORDER_DETAIL`) REFERENCES `OD_ORDER_DETAIL` (`ID_DLK_ORDER_DETAIL`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
